import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"恨天无把恨地无环","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/恨天无把恨地无环.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/恨天无把恨地无环.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/恨天无把恨地无环.md"};function _(l,a,p,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"恨天无把恨地无环",tabindex:"-1"},[s("恨天无把恨地无环 "),e("a",{class:"header-anchor",href:"#恨天无把恨地无环","aria-label":'Permalink to "恨天无把恨地无环"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),o('<h1 id="恨天无把恨地无环-1" tabindex="-1">恨天无把恨地无环 <a class="header-anchor" href="#恨天无把恨地无环-1" aria-label="Permalink to &quot;恨天无把恨地无环&quot;">​</a></h1><p>名称：恨天无把、恨地无环<br> 类型：大锤<br> 本质：魔幻<br> 价格：B+2000<br> 描述：自古以来，历朝历代都会出现这种人，天生神力、生撕虎豹，少部分会成为学识之人（孔），但大部分都成为了一员猛将，而这种人物一般都不喜欢太轻的兵器，而如意金箍棒只有一个而且归了大圣所有，其他人都只能退而求其次——一手提着一个大锤，双大锤挥舞遮天蔽日。而其中最佼佼的大力之人会看着天地叹息“恨天无把，恨地无环”。<br> 专业：锤<br> 武器伤害：19L<br> 特性：【重型武器】 【双手】【威猛3】<br> 体积：4<br> 伤害：钝击<br> 双锤：购买此武器会同时获得两个大锤【恨天无把】【恨地无环】，你必须双手各握持其中一把才能正常使效果生效，这是一对双持武器，每把都仍然具有【双手】特性，在攻击时，可以额外攻击触及范围内另外一个目标。</p><p>巨大的幻想：这两锤可不简单，不是正常兵器那种长杆带骨朵锤头的兵器，而是锤子占据整个武器的一半长度，另外一半为柄，以科学视角来看无法存在的兵器，本质源于人们对大锤的幻想。<br> 因为其巨大的体积使得其具有【碾压】特性并且武器伤害带来的破防为威猛。</p><p>神力的兵器：正因为其幻想的本质，其重量和威力都符合人们对其的憧憬。使用本武器必须使用力量为主属性进行攻击，随着你的力量越发超凡，武器的威力也越发强大。<br> 该武器额外提升你【传奇力量】*2L+1L的武器伤害，并且伴随你势大力沉的攻击，被你攻击的目标都感到手中武器发出颤抖需要以力量-武技-对应武器专业对抗攻击伤害，对抗失败则武器脱手，这是一个每轮一次的附带击落武器效果；除此之外，当你以该武器进行全力攻击时，不再减少基础防御。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
